import{_ as a}from"./chunks/visualization.BZec6wzB.js";import{_ as t,o as r,c as o,ag as i}from"./chunks/framework.BCNEhLBE.js";const u=JSON.parse('{"title":"Overview","description":"","frontmatter":{},"headers":[],"relativePath":"components/overview.md","filePath":"components/overview.md","lastUpdated":1773564957000}'),n={name:"components/overview.md"};function s(l,e,h,p,d,c){return r(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h1><p>Elena introduces an approach called <strong>“Progressive Web Components”:</strong></p><p>A <a href="https://arielsalminen.com/2026/progressive-web-components/" target="_blank" rel="noreferrer">Progressive Web Component</a> is a native Custom Element designed in two layers: a base layer of HTML and CSS that renders immediately, without JavaScript, and an enhancement layer of JavaScript that adds reactivity, event handling, and more advanced templating.</p><p>There are three types of Progressive Web Components:</p><h2 id="_1-composite" tabindex="-1">1. Composite <a class="header-anchor" href="#_1-composite" aria-label="Permalink to &quot;1. Composite&quot;">​</a></h2><p>Composite Components wrap and enhance the HTML composed inside them. All of their HTML and CSS lives in the Light DOM. You could also call these <a href="https://adactio.com/journal/20618" target="_blank" rel="noreferrer">HTML Web Components</a>.</p><h2 id="_2-primitive" tabindex="-1">2. Primitive <a class="header-anchor" href="#_2-primitive" aria-label="Permalink to &quot;2. Primitive&quot;">​</a></h2><p>Primitive Components are self-contained and render their own HTML. All of their CSS lives in the Light DOM together with the base HTML required for rendering the initial state.</p><h2 id="_3-declarative" tabindex="-1">3. Declarative <a class="header-anchor" href="#_3-declarative" aria-label="Permalink to &quot;3. Declarative&quot;">​</a></h2><p>Declarative Components are a hybrid of these and utilize <a href="/elena/components/templates#declarative-shadow-dom">Declarative Shadow DOM</a>.</p><img src="'+a+'" alt="This image visualizes the three types of Progressive Web Components."><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>Elena doesn’t force this taxonomy. They’re all just components, and you choose how to build yours. But since <a href="https://arielsalminen.com/2026/progressive-web-components/" target="_blank" rel="noreferrer">Progressive Web Components</a> is a design philosophy rather than a library feature, understanding the distinction between these approaches helps when deciding what fits your use case.</p></div>',12)])])}const _=t(n,[["render",s]]);export{u as __pageData,_ as default};
